import { NexusPreset } from '../../api/preset-api';
import { NexusEntityUnion, NexusEntity } from '../entity';
import { EntityConstructorType, EntityTypeKey } from '../entity-utils';
import { Modification } from '../../gen/audiotool/document/v1/document_service_pb';
import { Preset } from '../../gen/audiotool/document/v1/preset/v1/preset_pb';
import { DeepPartial } from 'utility-types';
import { PrimitiveField, PrimitiveType } from '../fields';
import { EntityQuery } from '../query/entity';
import { EntityWithOverwrites } from './build-clone-linked-entities';
import { InsertSampleOptions } from './build-insert-sample';
import { DevicePresetEntityType } from './prepare-preset';

/** A transaction builder can be used to make changes on a document.
 *
 * All changes made using the same transaction builder will be part of the same transaction,
 * and as such applied atomically to the backend.
 *
 * While a transaction builder exists, the document is locked, and no other builders can be created,
 * to avoid race conditions.
 *
 * To finish a transaction, call {@link send}, which will unlock the document and let other builders be created.
 * After {@link send} is called, all methods of the builder will throw.
 *
 * Modifications to the document with a builder are applied to the local document immediately,
 * and only sent to the backend when {@link send} is called.
 *
 * Note that if receiving a builder through {@link SyncedDocument.modify}, then {@link send} method is called
 * automatically once the function returns.
 * See [Overview](../../docs/overview.md#modifying-the-document) for more information.
 */
export type TransactionBuilder = {
    /** Create a new entity with default values */
    create<T extends EntityTypeKey>(name: T, args: EntityConstructorType<T>): NexusEntityUnion<T>;
    /** Update a primitive field value */
    update<P extends PrimitiveType>(field: PrimitiveField<P, "mut">, value: P): void;
    /** Try to update a primitive field. Don't throw if it fails; return a string explaining the error
     * instead. If this returns `undefined`, the update was applied. Useful when e.g. a user enters a value
     * and it's not possible to know if the value is valid or not.
     */
    tryUpdate<P extends PrimitiveType>(field: PrimitiveField<P, "mut">, value: P): string | undefined;
    /** Delete an entity with id `id` from the document.
     * Throws if another entity references it; use {@link removeWithDependencies} instead.
     */
    remove(idOrEntity: string | NexusEntity): void;
    /** Delete an entity with `id`, after all entities with pointers to it, transitively,
     * are deleted. In other words, remove entity `id`, after all entities are deleted
     * that would result in dangling pointers if `id` was removed.
     *
     * # Example
     * Let's say we have entities `a`, `b`, `c`, `d`, `e`, with pointers between each
     * other like this:
     *
     * ```text
     *   a ─► b ─┐
     *   │       ├──► d ─► e
     *   │       │
     *   └──► c ─┘
     * ```
     *
     * Then calling `removeWithDependencies(d.id)` will remove all entities except `e`,
     * in an order that keeps all existing pointers valid after every modification.
     */
    removeWithDependencies(idOrEntity: string | NexusEntity): void;
    /** Clone an existing entity, optionally overwriting some fields.
     *
     * Note that ts by default doesn't correctly type the output. To get correctly
     * typed output, do:
     * ```
     * const tonematrix = t.create("tonematrix", {})
     * const tonematrix2 = t.clone<"tonematrix">(tonematrix)
     * ```
     */
    clone<T extends EntityTypeKey>(entity: NexusEntity<T>, args?: DeepPartial<EntityConstructorType<T>>): NexusEntityUnion<T>;
    /** Clone a list of entities, in such a way that pointers that
     * are both from to entities in this list are updated to point to
     * the cloned versions. The resulting `creates` command are ordered in such a way
     * that all pointers are always valid, and no transaction errors occur.
     *
     * Each element in the past list can either be an entity itself, or an object
     * ```
     * {
     *  entity: NexusEntity<T>,
     *  overwrites?: ConstructorTypes[T]
     * }
     * ```
     * where `overwrites` work the same as the second parameter of `t.clone()` or `t.create()`.
     *
     * Pointers from and to entities not in the list remain unchanged, unless overwritten.
     *
     * Returns the cloned version of the entities in order. Robust towards duplicates
     * in the passed entities list.
     *
     * # Example
     *
     * Let's say we have entities `a`, `b`, `c`, `d`, `e`, with pointers between each
     * other like this:
     *
     * ```text
     *
     *  a ──► b ──► c ──► d
     *              ▲
     *              │
     *              e
     * ```
     *
     * And we call `cloneLinked(b, c)`. Then:
     * * the relationship between `b` and `c` is updated to duplicates
     * * relationships from `b` or `c` to other entities remain untouched
     * * relationships from other entities to `b` or `c` remain untouched
     *
     * Leading to a graph like this:
     *
     * ```text
     *
     *        b'──► c' ───┐
     *                    ▼
     *  a ──► b ──► c ──► d
     *              ▲
     *              │
     *              e
     * ```
     *
     *
     * If overwrite arguments are given for a specific entity, they overwrite any value
     * _after_ the links have been adjusted.
     *
     */
    cloneLinked(...entities: (EntityWithOverwrites | NexusEntity)[]): NexusEntity[];
    /** Apply a preset to a given entity. The preset is a special transaction. */
    applyPresetTo(entity: NexusEntity<DevicePresetEntityType>, preset: NexusPreset): void;
    /** Create a new device of the preset's target type and immediately apply the
     * preset to it.
     *
     * Equivalent to:
     * ```ts
     * const device = t.create(preset.entityType, {})
     * t.applyPresetTo(device, preset)
     * ```
     *
     * Useful together with {@link PresetsAPI.getInstrument} /
     * {@link PresetsAPI.getDrums}:
     * ```ts
     * const frenchHorn = await client.presets.getInstrument("french-horn")
     * await nexus.modify((t) => {
     *   const gakki = t.createDeviceFromPreset(frenchHorn)
     *   // ...
     * })
     * ```
     */
    createDeviceFromPreset<T extends DevicePresetEntityType>(preset: NexusPreset<T>): NexusEntityUnion<T>;
    /** Create a preset of a given entity. This doesn't modify the nexus document.  */
    createPresetFor(entity: NexusEntity<DevicePresetEntityType>): Preset;
    /**
     * Insert a sample into the timeline, creating all required entities; {@link AudioDevice}
     * {@link AudioTrack},{@link AutomationCollection}, {@link Sample} and {@link AudioRegion}.
     *
     * @param sample - The sample to insert. Anything with `name` /
     * `durationSeconds` / optional `bpm` is accepted — typically:
     * - a {@link SampleMeta} returned by {@link SamplesAPI.get} or
     *   {@link SamplesAPI.list}
     * - the resolved value of {@link SampleUpload.ready} (also a
     *   {@link SampleMeta}), returned by {@link SamplesAPI.upload}
     * - a plain object `{ name, durationSeconds, bpm? }` when you already
     *   know the duration locally (e.g. right after `upload.uploaded`
     *   resolves but before processing completes — see the last example
     *   below).
     * @param options - Insertion options like where in time, how long, how to loop, which track to attach to, etc.
     * @returns The created {@link AudioRegion} entity
     *
     * # Examples:
     *
     * ### Insert a sample retrieved from the backend
     * You can use sample objects returned by {@link SamplesAPI.get}, {@link SamplesAPI.list}, or {@link SamplesAPI.download}:
     *
     * ```typescript
     * // fetch some sample
     * const sample = await at.samples.get("samples/abc-123")
     * if (sample instanceof Error) throw sample
     * ```
     *
     * After the method completes, get the transaction builder to start modifying:
     * ```ts
     * const t = await nexus.createTransaction()
     * ```
     *
     * #### Insert at time 0
     *
     * Create track, region, cable, mixer channel, etc:
     * ```ts
     * t.insertSample(sample)
     * ```
     *
     * #### Insert into existing audio track:
     * ```ts
     * const track: NexusEntity<"audioTrack"> = ...
     * t.insertSample(sample, { attachTo: track })
     * ```
     *
     * #### Insert into new track on existing audio device:
     * ```ts
     * const device: NexusEntity<"audioDevice"> = ...
     * t.insertSample(sample, { attachTo: device })
     * ```
     *
     * #### Make it play in sync with the metronome
     * To make it play in sync with the metronome, you have to tell audiotool
     * how fast your sample should play relative to the metronome. You can do this
     * by passing in either the sample's own BPM, or by the sample's duration in music time (bars).
     *
     *
     * ```ts
     * t.insertSample(sample, {
     *    sample: { bpm: 120 }
     *  })
     * ```
     * ```ts
     * t.insertSample(sample, {
     *  sample: { musicDurationTicks: Ticks.Bars(3) }
     *  })
     * ```
     * #### Position the sample
     *
     * Position at bar 1, duration 3 bars, loop if sample is shorter:
     * ```ts
     * t.insertSample(sample, {
     *   sample: { bpm: 120 },
     *   region: { positionTicks: Ticks.Bars(1), durationTicks: Ticks.Bars(3) },
     *   loop: true,
     * })
     * ```
     * #### Loop specific sections of the sample
     * ```ts
     * t.insertSample(sample, {
     *   sample: { bpm: 120 },
     *   region: { positionTicks: Ticks.Bars(1), durationTicks: Ticks.Bars(9) },
     *   loop: { startTicks: Ticks.Bars(2), durationTicks: Ticks.Bars(2) },
     * })
     * ```
     *
     * ### Upload and insert a new sample
     *
     * If you have a local sample, you have to upload it first. See the
     * "Insert before processing completes" example below if you want to insert
     * earlier, before the backend has finished transcoding.
     *
     * ```typescript
     * const file: File = ...
     * const upload = await at.samples.upload({ file, displayName: "My Sample", bpm: 120 })
     * if (upload instanceof Error){
     *   throw upload
     * }
     *
     * // wait for the bytes to be on the server - after this point the user
     * // can safely close the tab.
     * const uploaded = await upload.uploaded
     * if (uploaded instanceof Error){
     *   throw uploaded
     * }
     *
     * // wait for backend processing (transcoding, duration, waveform).
     * const sample = await upload.ready
     * if (sample instanceof Error){
     *   throw sample
     * }
     *
     * // `sample` is a SampleMeta — pass it directly.
     * await nexus.modify(t => {
     *   t.insertSample(sample)
     * })
     * ```
     *
     * ### Insert before processing completes
     *
     * ```typescript
     * const upload = await at.samples.upload({ file, displayName: "My Sample", bpm: 120 })
     * if (upload instanceof Error){
     *   throw upload
     * }
     *
     * // you should wait for this point - if the user leaves before upload completes, the project will contain a broken sample.
     * const uploaded = await upload.uploaded
     * if (uploaded instanceof Error){
     *   throw uploaded
     * }
     *
     * // The sample is uploaded, we can insert into the project, but we need the sample's duration.
     * // In the web, you can do this as follows. Node.js/Bun/Deno may differ:
     * const context = new AudioContext()
     * const decoded = await context.decodeAudioData(await file.arrayBuffer()) // throws if decoding fails!
     * await context.close()
     *
     * await nexus.modify(t => {
     *   t.insertSample(
     *     {
     *       name: upload.name,
     *       durationSeconds: decoded.duration,
     *     },
     *     {
     *       sample: { bpm: 120 }
     *     }
     *   )
     * })
     * ```
     *
     */
    insertSample(sample: {
        name: string;
        durationSeconds: number;
        bpm?: number;
    }, options?: InsertSampleOptions): NexusEntity<"audioRegion">;
    /**
     * Release the transaction lock and send the modifications to the backend. After this method
     * is called, this `TransactionBuilder` can't be used anymore.
     */
    send(): void;
    /** Allows querying all entities of the document.  */
    entities: EntityQuery;
    /**
     * @internal
     * Add a generic modification message to this transaction. This is for internal use. */
    _addModification(modification: Modification): void;
};
/**
 * SafeTransactionBuilder type is used in places where we want to indicate that
 * 'send()' method of TransactionBuilder instance is already handled somewhere else
 * and shouldn't be called.
 */
export type SafeTransactionBuilder = Omit<TransactionBuilder, "send">;
/** Create a transaction builder. The transaction builder as an abstraction that allow easy
 * building of modifications. It's used in the `createTransaction` method of the `NexusDocument` class.
 */
export declare const transactionBuilder: (opts: {
    /** Query the current state of the document. For the nexus document to work as intended,
     * modifications applied using `applyModification` should immediately be reflected
     * in the query.
     */
    query: EntityQuery;
    /** Modifications created during this transaction. If `throwIfInvalid` is false, it should
     * return `string` in case an error occurs, otherwise it should throw an error or return undefined.
     *
     * The modifications must immediately be applied to `query`, otherwise the builder will throw.
     */
    applyModification: (mod: Modification, throwIfInvalid: boolean) => string | void;
    /** Called when `t.send()` is called, and the transaction becomes "invalid". */
    finish?: () => void;
}) => TransactionBuilder;
/** Thrown when a method of the builder is called after `send` has already been called. */
export declare class CallAfterSendError extends Error {
    constructor(methodName: string);
}
